    case fooEnum(Proto3Unittest_TestOneof2.NestedEnum)
  }

  enum NestedEnum: SwiftProtobuf.Enum, Swift.CaseIterable {
    typealias RawValue = Swift.Int
    case unknown // = 0
    case foo // = 1
    case bar // = 2
    case baz // = 3
    case UNRECOGNIZED(Swift.Int)

    init() {
      self = .unknown
    }

    init?(rawValue: Swift.Int) {
      switch rawValue {
      case 0: self = .unknown
      case 1: self = .foo
      case 2: self = .bar
      case 3: self = .baz
      default: self = .UNRECOGNIZED(rawValue)
      }
    }

    var rawValue: Swift.Int {
      switch self {
      case .unknown: return 0
      case .foo: return 1
      case .bar: return 2
      case .baz: return 3
      case .UNRECOGNIZED(let i): return i
      }
    }

    // The compiler won't synthesize support with the UNRECOGNIZED case.
    static let allCases: [Proto3Unittest_TestOneof2.NestedEnum] = [
      .unknown,
      .foo,
      .bar,
      .baz,
